+            crate::assert_with_log!(
+                recv_path.as_ref() == Some(&client_path),
+                "recv addr",
+                Some(&client_path),
+                recv_path.as_ref()
+            );
+        });
+        crate::test_complete!("test_datagram_peek_from");
+    }
